# Bayesianlibrary(rjags)# Bayesian unpenalized linear model with multivariate meta-analysis or mixing of MCMC samplesBayesian_unpenalized_linear_model <- function(data,                         newX,                         covariate_names,                         outcome = "y",                        treatment = "treatment",                          second_stage # Bayesian MA or mixing of MCMC samples                        ){	Bayesian.LM.obj <- BayesianLM(studies_data = data,					n.covariates = length(covariate_names),					nstudies = length(data),					cov_names = covariate_names,                     outcome = outcome,                    treatment = treatment)	newX.matrix <- as.matrix(newX)	if(second_stage == "Bayesian-MA"){		parameters_to_meta_analyze <- Bayesian.LM.obj[[1]]		Bayesian_meta_analysis <- second_stage(obj_first_stage = parameters_to_meta_analyze)		predictions <- Bayesian_meta_analysis["theta_delta", "Estimate"] + newX.matrix %*% ss[startsWith(rownames(ss), "gamma"), "Estimate"]	} else {		MCMC_samples_to_mix <- Bayesian.LM.obj[[2]]		predictions <- second_stage_ITE(covariates_test_data = newX.matrix,			posterior_samples = MCMC_samples_to_mix)		}	return(predictions)}# Bayesian LASSO with mixing of MCMC samplesBayesian_LASSO <- function(data, newX, covariate_names, outcome = "y", treatment = "treatment"){	n_covariates <- length(covariate_names)	studies_means <- do.call(rbind, data_training[[i]][[j]]) %>%       group_by(ID_study) %>%       summarize(x_1 = mean(x_1), x_2 = 0,                x_3 = mean(x_3), x_4 = 0,                x_5 = mean(x_5), x_6 = 0,                x_7 = mean(x_7), x_8 = 0)         studies_sds <- do.call(rbind, data_training[[i]][[j]]) %>%       group_by(ID_study) %>%       summarize(x_1 = sd(x_1), x_2 = 1,                x_3 = sd(x_3), x_4 = 1,                x_5 = sd(x_5), x_6 = 1,                x_7 = sd(x_7), x_8 = 1)        # train_dataset <- do.call(rbind, data_training[[i]][[j]])    std_data <- matrix(ncol = n_covariates + 3, nrow = 0)    for(l in 1:nstudies){      data_lth_study <- data_training[[i]][[j]][[l]]      cov_raw <- data_lth_study[, covariate_names]      cov_std <- scale(cov_raw, center = studies_means[l, -1],                       scale = studies_sds[l, -1])      std_data <- rbind(std_data, cbind(l, cov_std, data_lth_study[[treatment]],                                        data_lth_study[[response]]))    }        colnames(std_data) <-  c("ID_study",  ,"treatment", "y")        std_data <- as.data.frame(std_data)        p <- BayesLASSO.I_stage(studies_data = std_data,                             n.covariates = n_covariates,                             nstudies = nstudies)        cov <- data_testing[[i]][[j]] %>% select(starts_with("x")) %>% as.matrix()        predictions[, j] <- second_stage_LASSO(covariates_test_data = cov,                                            posterior_samples = p,                                           s.means = studies_means,                                           s.sds = studies_sds) }   